def compute_score() -> tuple[str, float]:
    modified_nums = [s[1].slide_number for s in ppt_diff.modified_slides]
    added_nums = [s.slide_number for s in ppt_diff.added_slides]
    removed_nums = [s.slide_number for s in ppt_diff.removed_slides]
    # Only slide 8 may be in the lists
    extraneous_mod = any(n != 8 for n in modified_nums)
    extraneous_add = any(True for _ in added_nums)
    extraneous_rem = any(True for _ in removed_nums)
    if not extraneous_mod and not extraneous_add and not extraneous_rem:
        return "No extraneous changes to other slides.", 1.0
    else:
        issue = []
        if extraneous_mod:
            issue.append(f"Slides modified besides slide 8: {modified_nums}")
        if extraneous_add:
            issue.append("Slides were added.")
        if extraneous_rem:
            issue.append("Slides were removed.")
        return "; ".join(issue), 0.0

def compute_score() -> tuple[str, float]:
    # Accept minor edge-case (e.g., placeholder animation removed if replaced)
    # Here, only score 0 if there are newly added animations/transitions unrelated to this slide
    if ppt_diff.added_animations or ppt_diff.added_transitions:
        return "Extraneous animations or transitions were added.", 0.0
    if ppt_diff.removed_animations or ppt_diff.removed_transitions:
        # Removing old placeholder animation is acceptable if placeholder was replaced
        return "Animations or transitions were removed.", 1.0  # Acceptable if part of placeholder removal
    return "No extraneous animations or transitions added.", 1.0
